// "From start to live" — heading + 3 step cards that translate up/down with
// scroll, one by one. Props: { content, theme }. Neutral placeholder media only.
import { useRef, useState, useEffect } from "react";
import { motion, useScroll, useTransform, useSpring, useReducedMotion } from "framer-motion";

export default function Section({ content, theme }) {
  const c = content || {};
  const title = c.title || "From start to live in a few steps";
  const items = (c.items && c.items.length ? c.items : [
    { title: "Install and activate", text: "Download your starter file, then install and activate it from the plugins menu in a couple of clicks." },
    { title: "Start a new page", text: "Go to Pages, add a new one, and open the visual editor to begin building with full creative freedom." },
    { title: "Design and publish", text: "Design your pixel-perfect layout with the full editor and drag-and-drop ease, then publish with confidence." },
  ]);

  const rootRef = useRef(null);
  const [w, setW] = useState(1280);
  useEffect(() => {
    const el = rootRef.current;
    if (!el) return;
    const ro = new ResizeObserver(() => setW(el.clientWidth));
    ro.observe(el);
    return () => ro.disconnect();
  }, []);
  const narrow = w < 720, mid = w >= 720 && w < 1040;
  const cols = narrow ? "1fr" : mid ? "1fr 1fr" : "1fr 1fr 1fr";
  const reduce = useReducedMotion();

  return (
    <section ref={rootRef} style={{
      background: theme.backgroundColor, color: theme.textColor, fontFamily: theme.bodyFont,
      padding: narrow ? "48px 20px" : "96px 64px",
    }}>
      <div style={{ maxWidth: 1240, margin: "0 auto" }}>
        <h2 style={{
          fontFamily: theme.headingFont, fontWeight: 800, letterSpacing: "-0.02em",
          lineHeight: 1.05, fontSize: narrow ? 34 : 54, margin: 0, maxWidth: 820,
        }}>{title}</h2>

        <div style={{ marginTop: narrow ? 40 : 80, display: "grid", gridTemplateColumns: cols, gap: narrow ? 40 : 28, alignItems: "start" }}>
          {items.map((it, i) => (
            <StepCard key={i} item={it} index={i} narrow={narrow} reduce={reduce} theme={theme} />
          ))}
        </div>
      </div>
    </section>
  );
}

function StepCard({ item, index, narrow, reduce, theme }) {
  const ref = useRef(null);
  // Progress as THIS card travels through the viewport (element-based → works in
  // preview frames). Reverses naturally on scroll up.
  const { scrollYProgress } = useScroll({ target: ref, offset: ["start 0.95", "start 0.55"] });
  const yRaw = useTransform(scrollYProgress, [0, 1], [64, 0]);
  const opRaw = useTransform(scrollYProgress, [0, 1], [0, 1]);
  const y = useSpring(yRaw, { stiffness: 90, damping: 20, mass: 0.4 });
  const opacity = useSpring(opRaw, { stiffness: 90, damping: 20 });

  const faint = theme.mutedTextColor;
  // Desktop "staircase" offset like the reference (middle card sits lower).
  const stagger = narrow ? 0 : index === 1 ? 48 : 0;

  return (
    <motion.div ref={ref} style={{ marginTop: stagger, y: reduce ? 0 : y, opacity: reduce ? 1 : opacity }}>
      <Media theme={theme} height={narrow ? 240 : 320} />
      <div style={{ display: "flex", alignItems: "center", gap: 10, margin: "18px 0 14px" }}>
        <svg width="20" height="20" viewBox="0 0 24 24" fill="none" style={{ color: theme.accentColor }}>
          <path d="M3 12h15m0 0-5-5m5 5-5 5" stroke="currentColor" strokeWidth="1.9" strokeLinecap="round" strokeLinejoin="round" />
        </svg>
        <span style={{ fontSize: 14, fontWeight: 700, letterSpacing: "0.02em" }}>Step {index + 1}</span>
      </div>
      <h3 style={{ margin: "0 0 10px", fontFamily: theme.headingFont, fontWeight: 700, fontSize: narrow ? 24 : 28 }}>{item.title}</h3>
      <p style={{ margin: 0, fontSize: 16, lineHeight: 1.6, color: faint, maxWidth: 380 }}>{item.text}</p>
    </motion.div>
  );
}

function Media({ theme, height }) {
  const line = theme.borderColor, soft = theme.surfaceColor, faint = theme.mutedTextColor;
  return (
    <div style={{ height, borderRadius: theme.radius || "16px", border: "1px solid " + line, background: soft, display: "grid", placeItems: "center" }}>
