      <div style={{ position: "relative", width: cardW, flex: "0 0 auto", aspectRatio: "3 / 4", borderRadius: 20, overflow: "hidden", background: p.tint }}>
        <div style={{ position: "absolute", inset: 0, display: "grid", placeItems: "center", color: "rgba(0,0,0,0.16)" }}>
          <svg width="72" height="72" viewBox="0 0 24 24" fill="none"><circle cx="12" cy="9" r="4" stroke="currentColor" strokeWidth="1.5" /><path d="M4.5 20c1.2-3.6 4-5.2 7.5-5.2S18.3 16.4 19.5 20" stroke="currentColor" strokeWidth="1.5" strokeLinecap="round" /></svg>
        </div>
        <div style={{ position: "absolute", left: 0, right: 0, bottom: 0, padding: 16, background: "linear-gradient(180deg, transparent, rgba(0,0,0,0.6))", color: "#ffffff" }}>
          <div style={{ fontSize: 15, fontWeight: 700 }}>{p.name}</div>
          <div style={{ fontSize: 12.5, opacity: 0.85, marginBottom: 8 }}>{p.role}</div>
          <div style={{ display: "flex", gap: 6, flexWrap: "wrap" }}>
            {p.tags.map((t, i) => (<span key={i} style={{ fontSize: 11, border: "1px solid rgba(255,255,255,0.5)", borderRadius: 999, padding: "3px 10px" }}>{t}</span>))}
          </div>
        </div>
      </div>
    );
  };
  const Row = () => (<div style={{ display: "flex", gap: 16, paddingRight: 16 }}>{people.map((p, i) => <Card key={i} p={p} />)}</div>);

  return (
    <section ref={rootRef} style={{ background: bg, color: text, fontFamily: theme.bodyFont, overflow: "hidden" }}>
      <div style={{ maxWidth: 860, margin: "0 auto", textAlign: "center", padding: narrow ? "48px 20px 0" : "72px 64px 0" }}>
        <span style={{ display: "inline-block", fontSize: 13.5, fontWeight: 700, color: accent, background: accent + "24", borderRadius: 999, padding: "8px 16px" }}>{eyebrow}</span>
        <motion.h1
          initial={reduce ? false : { opacity: 0, y: 18 }}
          whileInView={{ opacity: 1, y: 0 }}
          viewport={{ once: true, margin: "-40px" }}
          transition={{ duration: 0.5, ease: [0.22, 1, 0.36, 1] }}
          style={{ margin: "22px 0 0", fontFamily: theme.headingFont, fontWeight: 700, letterSpacing: "-0.02em", lineHeight: 1.06, fontSize: hSize, color: text }}
        >
          {title}
        </motion.h1>
        <p style={{ margin: "20px auto 0", maxWidth: 560, fontSize: narrow ? 16 : 19, lineHeight: 1.5, color: faint }}>{description}</p>
        <div style={{ marginTop: 30, display: "flex", justifyContent: "center" }}>
          <button type="button" style={{ border: 0, background: text, color: bg, borderRadius: 999, padding: "15px 32px", fontSize: 15, fontWeight: 600, cursor: "pointer", fontFamily: theme.bodyFont }}>{cta}</button>
        </div>
      </div>

      <div style={{ marginTop: narrow ? 36 : 56, paddingBottom: narrow ? 24 : 32 }}>
        {reduce ? (
          <div style={{ display: "flex", gap: 16, overflowX: "auto", padding: "0 20px" }}><Row /></div>
        ) : (
          <motion.div style={{ display: "flex", width: "max-content" }} animate={{ x: ["0%", "-50%"] }} transition={{ duration: 40, repeat: Infinity, ease: "linear" }}>
            <Row /><Row />
          </motion.div>
        )}
      </div>
    </section>
  );
}

// Dark site header: brand + nav links + a PAGES mega menu, a cart badge, and a
// solid CONTACT button. Collapses to a hamburger + drawer on small screens.
// Props: { content, theme }. Placeholder links + original copy only.
import { useRef, useState, useEffect } from "react";
import { motion, AnimatePresence, useReducedMotion } from "framer-motion";

export default function Section({ content, theme }) {
  const c = content || {};
  const brand = c.title || "Studio.";
  const contact = c.primaryButtonLabel || "Contact";

  const rootRef = useRef(null);
  const [w, setW] = useState(1200);
  useEffect(() => {
    const el = rootRef.current;
    if (!el) return;
    const ro = new ResizeObserver(() => setW(el.clientWidth));
    ro.observe(el);
    return () => ro.disconnect();
  }, []);
  const compact = w < 1000;

  const [openMega, setOpenMega] = useState(false);
  const [mobile, setMobile] = useState(false);
  const reduce = useReducedMotion();

  const accent = theme.accentColor;
  const dark = "#0b0b0f";
  const txt = "#ffffff";
  const muted = "rgba(255,255,255,0.6)";
  const line = "rgba(255,255,255,0.12)";
  const panel = "#17181c";
  const onAccent = "#0b0b0f";

  const links = ["Home", "Studio", "Services", "Works"];
  const mega = [
    { h: "Main Pages", items: ["Home 01", "Home 02", "Home 03", "About 01", "About 02", "About 03", "Work 01", "Work 02", "Work 03"] },
    { h: "Pages", items: ["Services", "Pricing", "Blog", "Career", "Contact", "Privacy Policy", "Terms of Use"] },
    { h: "Inner Pages", items: ["Services Single", "Work Single", "Blog Single", "Pricing Single", "Career Single"] },
    { h: "More", items: ["Style Guide", "License", "Changelog", "Password", "404"] },
  ];

  const Cart = () => (
    <span style={{ position: "relative", display: "inline-flex", color: txt }}>
      <svg width="24" height="24" viewBox="0 0 24 24" fill="none"><path d="M3.5 4.5H6l2.1 10.2a1 1 0 0 0 1 .8h7.5a1 1 0 0 0 1-.78L20.4 8H7" stroke="currentColor" strokeWidth="1.6" strokeLinecap="round" strokeLinejoin="round" /><circle cx="9.5" cy="19.5" r="1.4" fill="currentColor" /><circle cx="17" cy="19.5" r="1.4" fill="currentColor" /></svg>
      <span style={{ position: "absolute", top: -6, right: -8, minWidth: 16, height: 16, borderRadius: 999, background: accent, color: onAccent, fontSize: 10.5, fontWeight: 700, display: "grid", placeItems: "center", padding: "0 4px" }}>0</span>
    </span>
  );

  return (
    <section ref={rootRef} style={{ background: dark, color: txt, fontFamily: theme.bodyFont }}>
      <div style={{ position: "relative", maxWidth: 1320, margin: "0 auto", padding: compact ? "14px 20px" : "18px 28px", display: "flex", alignItems: "center", justifyContent: "space-between", gap: 16 }}>
        <span style={{ fontFamily: theme.headingFont, fontWeight: 800, fontSize: 20, letterSpacing: "-0.02em", color: txt }}>{brand}</span>

        {!compact && (
          <nav style={{ display: "flex", alignItems: "center", gap: 30, fontSize: 15, fontWeight: 600 }} onMouseLeave={() => setOpenMega(false)}>
            {links.map((l, i) => (<a key={i} href="#" style={{ color: i === 0 ? txt : muted, textDecoration: "none" }}>{l.toUpperCase()}</a>))}
            <button type="button" onMouseEnter={() => setOpenMega(true)} onClick={() => setOpenMega((v) => !v)} style={{ display: "inline-flex", alignItems: "center", gap: 6, background: "none", border: 0, color: openMega ? txt : muted, fontSize: 15, fontWeight: 600, cursor: "pointer", fontFamily: theme.bodyFont }}>
              PAGES <svg width="14" height="14" viewBox="0 0 24 24" fill="none" style={{ transform: openMega ? "rotate(180deg)" : "none", transition: "transform .2s" }}><path d="m6 9 6 6 6-6" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round" /></svg>
            </button>
          </nav>
        )}

        <div style={{ display: "flex", alignItems: "center", gap: compact ? 14 : 18 }}>
          {!compact && <Cart />}
          {!compact && (
            <button type="button" style={{ background: accent, color: onAccent, border: 0, borderRadius: 10, padding: "12px 22px", fontSize: 14, fontWeight: 700, letterSpacing: "0.02em", cursor: "pointer", fontFamily: theme.bodyFont }}>{contact.toUpperCase()}</button>
          )}
          {compact && (
            <button type="button" aria-label="Toggle menu" onClick={() => setMobile((v) => !v)} style={{ background: "none", border: 0, color: txt, cursor: "pointer", display: "grid", placeItems: "center" }}>
              <svg width="26" height="26" viewBox="0 0 24 24" fill="none">{mobile ? <path d="m6 6 12 12M18 6 6 18" stroke="currentColor" strokeWidth="1.8" strokeLinecap="round" /> : <path d="M4 7h16M4 12h16M4 17h16" stroke="currentColor" strokeWidth="1.8" strokeLinecap="round" />}</svg>
            </button>
          )}
        </div>

        <AnimatePresence>
          {!compact && openMega && (
            <motion.div
              initial={reduce ? false : { opacity: 0, y: 10 }}
              animate={{ opacity: 1, y: 0 }}
              exit={reduce ? {} : { opacity: 0, y: 10 }}
              transition={{ duration: 0.2, ease: [0.22, 1, 0.36, 1] }}
              onMouseEnter={() => setOpenMega(true)}
              onMouseLeave={() => setOpenMega(false)}
              style={{ position: "absolute", top: "100%", left: "50%", transform: "translateX(-50%)", marginTop: 8, width: "min(980px, 92%)", background: panel, border: "1px solid " + line, borderRadius: 20, padding: 28, display: "grid", gridTemplateColumns: "repeat(4, 1fr)", gap: 24, boxShadow: "0 30px 70px rgba(0,0,0,0.5)", zIndex: 20 }}
            >
              {mega.map((col, i) => (
                <div key={i}>
                  <p style={{ margin: "0 0 14px", fontSize: 16, fontWeight: 700, color: txt }}>{col.h}</p>
                  <ul style={{ listStyle: "none", margin: 0, padding: 0, display: "grid", gap: 12 }}>
                    {col.items.map((it, j) => (<li key={j}><a href="#" style={{ color: (i === 0 && j === 0) ? accent : muted, textDecoration: "none", fontSize: 15 }}>{it}</a></li>))}
                  </ul>
                </div>
              ))}
            </motion.div>
          )}
        </AnimatePresence>
      </div>

      <AnimatePresence>
        {compact && mobile && (
          <motion.div initial={reduce ? false : { opacity: 0, height: 0 }} animate={{ opacity: 1, height: "auto" }} exit={reduce ? {} : { opacity: 0, height: 0 }} transition={{ duration: 0.25, ease: [0.22, 1, 0.36, 1] }} style={{ overflow: "hidden", borderTop: "1px solid " + line }}>
            <div style={{ padding: "14px 20px 20px", display: "grid", gap: 2 }}>
              {links.map((l, i) => (<a key={i} href="#" style={{ color: i === 0 ? txt : muted, textDecoration: "none", fontSize: 16, fontWeight: 600, padding: "10px 0" }}>{l}</a>))}
              {mega.map((col, i) => (
                <div key={i} style={{ marginTop: 10 }}>
                  <p style={{ margin: "0 0 6px", fontSize: 12, textTransform: "uppercase", letterSpacing: "0.08em", color: "rgba(255,255,255,0.4)" }}>{col.h}</p>
                  <div style={{ display: "flex", flexWrap: "wrap", gap: "8px 16px" }}>
                    {col.items.map((it, j) => (<a key={j} href="#" style={{ color: muted, textDecoration: "none", fontSize: 14 }}>{it}</a>))}
                  </div>
                </div>
              ))}
              <div style={{ display: "flex", alignItems: "center", gap: 16, marginTop: 16 }}>
                <Cart />
                <button type="button" style={{ flex: 1, background: accent, color: onAccent, border: 0, borderRadius: 10, padding: "14px", fontSize: 15, fontWeight: 700, cursor: "pointer", fontFamily: theme.bodyFont }}>{contact}</button>
              </div>
            </div>
          </motion.div>
        )}
      </AnimatePresence>
    </section>
  );
}
